    question: "Use EventHandler standard delegate for events.",
    mathSolution: "Standard .NET event pattern with EventHandler.",
    codeSolution: "using System;\n\nclass Process\n{\n    // Standard EventHandler (no custom data)\n    public event EventHandler Started;\n    public event EventHandler Completed;\n    \n    public void Run()\n    {\n        Console.WriteLine(\"Process starting...\");\n        Started?.Invoke(this, EventArgs.Empty);\n        \n        System.Threading.Thread.Sleep(1000);\n        Console.WriteLine(\"Process completed\");\n        Completed?.Invoke(this, EventArgs.Empty);\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Process process = new Process();\n        \n        process.Started += (sender, e) => Console.WriteLine(\"  Event: Process started\");\n        process.Completed += (sender, e) => Console.WriteLine(\"  Event: Process completed\");\n        \n        process.Run();\n    }\n}",
    hint: "EventHandler is the standard .NET delegate for events without custom data.",
