    id: "cs_events_3",
    topicId: "cs_events",
    question: "Use EventHandler<TEventArgs> for events with custom data.",
    mathSolution: "Passing custom data with events.",
    codeSolution: "using System;\n\n// Custom EventArgs class\npublic class MessageEventArgs : EventArgs\n{\n    public string Message { get; set; }\n    public DateTime Timestamp { get; set; }\n    public int Priority { get; set; }\n}\n\nclass Messenger\n{\n    public event EventHandler<MessageEventArgs> MessageReceived;\n    \n    public void SendMessage(string message, int priority)\n    {\n        Console.WriteLine($\"Sending: {message}\");\n        \n        var args = new MessageEventArgs\n        {\n            Message = message,\n            Timestamp = DateTime.Now,\n            Priority = priority\n        };\n        \n        MessageReceived?.Invoke(this, args);\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Messenger messenger = new Messenger();\n        \n        messenger.MessageReceived += (sender, e) =>\n        {\n            Console.WriteLine($\"[RECEIVED] {e.Message}\");\n            Console.WriteLine($\"  Time: {e.Timestamp:T}, Priority: {e.Priority}\");\n        };\n        \n        messenger.SendMessage(\"Hello World\", 1);\n        messenger.SendMessage(\"Urgent message\", 5);\n    }\n}",
    hint: "Derive from EventArgs to pass custom data with events.",
